  movement_family = 'Vertical projection foundation',
  primary_phase_key = 'output',
  phase_subrole = 'jump_throw_explosive_power',
  primary_order_slot = 'squat_jump_to_stick',
  default_sets = 3,
  default_reps = 1,
  default_work_seconds = NULL,
  default_rest_seconds = 90,
  est_seconds_per_set = 65,
  movement_requirements = '{"primary_joint_actions":["jump pattern","land pattern","squat pattern"],"primary_tissues":[],"primary_motor_control_demands":["stacked ribs and pelvis","active foot tripod","knee tracks over toes","controlled landing or finish","Pain-free squat/hinge/landing pattern","Can follow cues and stop on command","Can keep posture and breathing under the planned speed"],"postural_shape":"stacked ribs and pelvis","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":2,"expression_quality":"Explosive contacts should look fast, quiet, tall, and repeatable; strength-support reps should look strong and technically consistent.","contraindication_flags":["Current lower-limb pain with jumping","Recent acute ankle/knee/hip injury without clearance","Inability to land or brace safely"]}'::jsonb,
  coaching_execution = '{"movement_description":"The athlete performs Squat Jump to Stick as a quality-first jump-height drill, emphasizing connects basic vertical force production to landing ownership so athletes do not separate takeoff height from safe finish position.","setup":["Set up in a clear open floor area with enough space for safe takeoff and landing. Explain the rep count, finish rule, and stop signal before starting."],"execution_steps":["Start in the prescribed stance with eyes up, ribs stacked, and feet active.","Create the intended dip, approach, contact, or load without rushing the setup.","Execute with the cue: Jump straight up, land where you started, and stick clean.","Land, rebound, or finish exactly as prescribed; reset fully before the next rep.","End the set as soon as speed, height, rhythm, alignment, or pain-free control degrades."],"coach_cues":["Jump straight up, land where you started, and stick clean.","Quiet feet","Tall posture","Full reset","Fast intent without fatigue chasing"],"quality_gate":["No pain or guarding","Foot, knee, and hip stay aligned","Contact is quiet and fast for jump work","Landing or finish is controlled","Next rep would look as good as the current rep"],"common_faults":["Chasing height after landing quality drops","Letting knees collapse inward","Losing trunk position or arm timing","Turning the drill into a conditioning station"],"regressions":["Lower amplitude or box height","Fewer contacts or reps","Planned version before reactive version","Two-leg version before single-leg version"],"progressions":["Add approach speed only after shape is owned","Increase amplitude before adding complexity","Progress from stick to rebound when landing is reliable","Use light external load only if speed remains crisp"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":[],"pairs_well_after":["dynamic warm-up","approach mechanics","low-volume strength support"],"good_for_sessions":["vertical jump height","jumping athletes"],"avoid_before":["fatigue-heavy conditioning","high-volume jump circuits","maximal lower-body strength immediately before testing"],"avoid_after":[],"do_not_use_when":[],"notes":"For jump-height sessions, pair fresh Output work before Capacity work. Do not bury high-skill jumping after fatigue."}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Film first working set from front and side to confirm foot-knee-hip alignment, trunk position, arm timing, and landing quality."],"internal_notes":[]}'::jsonb,
