  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Film first working set from front and side to confirm foot-knee-hip alignment, trunk position, arm timing, and landing quality."],"internal_notes":[]}'::jsonb,
