-- Barbell Hip Thrust (barbell-hip-thrust)
UPDATE coaching.exercise SET
  name = 'Barbell Hip Thrust',
  description = 'The athlete performs Barbell Hip Thrust as a quality-first jump-height drill, emphasizing raises hip-extension capacity that supports takeoff power, sprint approach mechanics, and posterior-chain reserve.',
  card_summary = 'Barbell Hip Thrust is a hip extension force support exercise for jumping athletes who need more vertical height. It targets raises hip-extension capacity that supports takeoff power, sprint approach mechanics, and posterior-chain reserve.',
